                $allNodes = array_keys($allNodes);
                
                // DFS cycle detection
                $WHITE = 0; $GRAY = 1; $BLACK = 2;
                $color = [];
                foreach ($allNodes as $n) { $color[$n] = $WHITE; }
                
                $hasCycle = false;
