                $dfs = function($node) use (&$dfs, &$graph, &$color, &$hasCycle, &$cycle, &$parent) {
                    $color[$node] = 1; // GRAY
                    if (isset($graph[$node])) {
                        foreach ($graph[$node] as $neighbor) {
                            if ($color[$neighbor] === 1) {
                                $hasCycle = true;
                                $cycle = "Cycle detected: $node -> $neighbor";
                                return;
                            }
                            if ($color[$neighbor] === 0) {
                                $dfs($neighbor);
                            }
                        }
                    }
                    $color[$node] = 2; // BLACK
                };
                
                // Need to use iteration for DFS due to closure capture limitation
                // Let's use a simpler approach
                $inStack = [];
                $visited = [];
                foreach ($allNodes as $n) {
