                        $stack = [[$start, 0]];
                        $pathMap = [$start => null];
                        $visited[$start] = true;
                        $inStack[$start] = true;
                        
                        while (!empty($stack)) {
                            $foundNext = false;
                            $current = $stack[count($stack)-1][0];
                            $idx = $stack[count($stack)-1][1];
                            
                            if (isset($graph[$current])) {
                                $neighbors = $graph[$current];
                                while ($idx < count($neighbors)) {
                                    $next = $neighbors[$idx];
                                    $stack[count($stack)-1][1] = $idx + 1;
                                    
                                    if ($inStack[$next]) {
                                        $hasCycle = true;
                                        $cycle = "Cycle detected involving: $next";
                                        break 3;
                                    }
                                    if (!$visited[$next]) {
